var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이쪽은 조용하고…….","JPN":"こっちは静かだし……","ENG":"Over there’s quiet...","TWN":"這裡很安靜……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이쪽도 조용하고…….","JPN":"こっちもよし……","ENG":"There too...","TWN":"這裡也很安靜……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아무도 없어요. 나오셔도 돼요.","JPN":"誰もいません。出てきてもいいですよ。","ENG":"It’s all clear. You can come out now.","TWN":"沒人，可以出來囉。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으음……. 손님도 오셨는데 집을 비우면 안 돼요…….","JPN":"ううん……お客さんが来てるのに家を空けたらだめですよ……","ENG":"But... We can’t just leave the house. We have a guest.","TWN":"嗯……有客人來，家裡怎麼可以沒有人……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"총소리는 무서워요……. 어서 집에 들어가요…….","JPN":"銃の音は怖いです……早く家に戻りましょう……","ENG":"Gunshots are so frightening... Let’s go home.","TWN":"槍聲好恐怖……我們快回家……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"죄송해요, 아주머니. 지금 집 근처에 무서운 사람들이 나타났어요.","JPN":"すみません、おばさん。今家の近くに怖い人たちが来てるんです。","ENG":"I’m sorry, Madam. There are some very scary people near our house right now.","TWN":"伯母，對不起，現在我們家附近有很多可怕的人，"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"무서워도 조금만 참으세요. 아셨죠?","JPN":"怖くても少し我慢してください。ね？","ENG":"I know it’s scary, but try to bear with it for a little while. Please.","TWN":"所以就算你會怕也要忍耐一下，好嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안젤라 씨, 여기서 보안국 청사로 가려면 어떻게 해야 돼요?","JPN":"アンジェラさん、ここから保安局庁舎までどうやって行くんですか？","ENG":"Angela, how do you get to the National Security office from here?","TWN":"安潔拉，你知道從這裡要怎麼去安全局嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"보안국이면…… 큰길로 나가서 전차를 타는 게 제일 빠를 거야.","JPN":"保安局なら……大通りに出て、電車に乗るのが一番早いと思うわ。","ENG":"National Security... The fastest way would be to get on the main street and take a tram.","TWN":"安全局嗎……出去到大馬路上，攔一台戰車搭便車是最快的。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"좋아요. 머리가 완전히 돌아 버렸어도 보안국 청사까지는 못 올 거예요.","JPN":"よし。完全に頭がいかれても、保安局庁舎までは来れないでしょう。","ENG":"Good. Even if they were completely out of their minds they’d never try for us at the National Security office.","TWN":"很好！他們再怎麼發神經，也不敢跑到安全局來吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제가 앞장설게요. 언제 어디서 저 미친놈들이 덮칠지 모르니까.","JPN":"私が先頭に立ちます。いつ、どこであの狂人たちが襲ってくるかわかりませんから。","ENG":"I’ll lead the way. We don’t know when and where those crazy bastards will come from.","TWN":"不知道那些瘋子什麼時候，會從哪裡蹦出來，我來打頭陣吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"괜찮니? 손을 무척 떨고 있는데…….","JPN":"大丈夫？　手がすごく震えてるけど……","ENG":"Are you okay? You’re hands are shaking...","TWN":"你還好嗎？你手抖得很厲害欸……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래도 별 수 없잖아요. 밑도 끝도 없이 떠맡긴 했어도 일단은 사람 목숨이 걸린 일인데.","JPN":"でも仕方ないでしょう。やぶから棒に任せられましたけど、一応人の命がかかったことですし。","ENG":"I have no choice but to do. I just took it all of a sudden, but this is a matter of life or death.","TWN":"有什麼辦法！雖然我是臨危受命，但這可是人命關天的事！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저한테 레아 씨처럼 의연함까지 기대하지는 마세요.","JPN":"私にレアさんのような落ち着きぶりまでは期待しないでください。","ENG":"Don’t expect me to be as brave as Leah.","TWN":"不過你們不要期待我會像蕾亞小姐一樣堅強。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"총을 쏴 대는데 냅다 뛰어나가는 쪽이 누가 봐도 겁을 상실한 거죠.","JPN":"弾雨の中でいきなり飛び出すなんて誰が見てもおかしいです。","ENG":"It’s obvious she lost her fear. Who wouldn’t be scared in a place like this?","TWN":"在一片槍林彈雨之中，還能那樣衝出去，很明顯是不怕死的人吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"걱정하지 마. 레아는 이런 곳에서 죽지 않아.","JPN":"大丈夫よ。レアはこんなところで死んだりしないわ。","ENG":"Don’t worry. Leah won’t die in a place like this.","TWN":"你放心，蕾亞不會死在這種地方的！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"굉장히 확신에 찬 대답이네요.","JPN":"すごく確信してますね。","ENG":"How can you be so sure?","TWN":"你的回答還真有信心。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"옆에서 아주 오래 지켜봤거든. 궁지에 몰려도 결국 언제나 답을 찾아내는 사람이야.","JPN":"もう長い間そばで見てきたからね。窮地に陥っても結局いつも答えを探し出す人なの。","ENG":"I’ve known her for a very long time. No matter how difficult things get, she always finds a solution.","TWN":"我在她身邊這麼久，她的能耐我最清楚不過，她就算被逼到絕境，最後也一定會找到出路的！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……사실 그렇게 잘난 사람이 아니라면요?","JPN":"……本当はそんなにすごい人じゃなかったらどうします？","ENG":"...What if she’s not so smart?","TWN":"……她似乎不像你說的那麼厲害欸？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"알게 된 지는 얼마 안 됐지만, 안젤라 씨에게 많이 의지하는 것 같았어요.","JPN":"知り合ったばっかりですけど、アンジェラさんに結構頼ってるみたいでした。","ENG":"I haven’t known you guys for a long time but, she really seems to have relied on you a lot.","TWN":"雖然我跟她才認識沒多久，但可以感覺得出來她很依賴你。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"우후후, 정말?","JPN":"うふふ、本当？","ENG":"Fuu fuu, really?","TWN":"呵呵呵，是嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"응, 응. 그럴 거야. 난 보살피는 일만큼은 옛날부터 주변의 다른 친구들보다 잘했거든.","JPN":"うん、うん。そうでしょうね。私、昔から面倒を見ることだけは他の人より上手だったの。","ENG":"Yeah, yeah. I guess so. I’ve always been better than others at caring for people.","TWN":"嗯嗯，應該是吧？畢竟我從以前就很會照顧人。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그래서 말인데, 중사님. 언니가 잠깐 실례 좀 할게.","JPN":"それでだけど、軍曹さん。お姉ちゃんがちょっと失礼するね。","ENG":"Speaking of which, Sergeant. Excuse me for a moment.","TWN":"所以中士，姊姊先跟你說聲不好意思囉！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"크헤윽!?","JPN":"くふぇっ！？","ENG":"W-What!?","TWN":"唔唔？！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"왜 사람 뒷덜미를 낚아채─","JPN":"なんで人の襟首をつか――","ENG":"Why did you grab─","TWN":"幹嘛突然勾人家的脖子─"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"─주셔서 감사합니다.","JPN":"――んでくれてありがとうございます。","ENG":"...Thank you.","TWN":"─謝謝救命之恩。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_F","text":{"KOREA":"제기랄, 한 발짝만 더 나왔으면 명중이었는데!","JPN":"クソ、もう一歩出てたら命中してたのに！","ENG":"Damn it, if she kept walking one more step, I’d have hit her!","TWN":"可惡！差一點就打中了！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_D","text":{"KOREA":"이 멍청한 놈아! 그러다 죽이기라도 하면 어쩌려고!","JPN":"このアホが！　それで殺しちまったらどうすんだよ！","ENG":"You idiot! What if you killed her?","TWN":"你這個蠢蛋！萬一真的打中她怎麼辦！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_D","text":{"KOREA":"숨이 붙어 있어야 그년 눈 앞에서 산 채로 껍질을 벗길 거 아냐!","JPN":"死んじまったら、あの女の前で生きたまんま皮を剥げねぇだろ！","ENG":"We need her alive, so we can take her apart later in front of that bitch!","TWN":"要先留她一命，才能在那女的面前好好凌虐她！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_F","text":{"KOREA":"닥쳐! 우리가 대장님 복수하러 왔지 그딴 장난질 온 줄 알아?!","JPN":"黙れ！　俺らの目的は隊長の仇討ちなんだよ、そんな遊びはどうでもいい！！","ENG":"Shut up! We’re here to get revenge for the Captain. You think it's a joke?","TWN":"住嘴！我們是來替隊長報仇的！你以為是來玩的嗎？！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_F","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"또 수류탄……?! 피해요, 안젤라 씨!!","JPN":"また手榴弾……！？　アンジェラさん、避けて！！","ENG":"Another grenade...?! Get back, Angela!","TWN":"又是手榴彈……？！安潔拉小姐，快躲起來！！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으……. 아으…….","JPN":"う……あぅ……","ENG":"Oof... Ugh...","TWN":"呃……呃呃……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"세상에……! 중사님 얼굴이 피투성이야……!","JPN":"そんな……！　軍曹さんの顔が血まみれに……！","ENG":"Oh my...! Sergeant, your face is covered in blood!","TWN":"天啊……！中士，你的臉都流血了……！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이, 이 정도는 금방 나으니까……. 아주머니부터…….","JPN":"こ、このくらいはすぐ治りますから……おばさんを先に……","ENG":"This, this will get better in no time... Just, take care of madam...","TWN":"喔…這點小傷很快就沒事了……先把伯母……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"아아, 사람들, 사람들이 와…….","JPN":"ああ、人、人が来る……","ENG":"Ah, more people, more people are coming...","TWN":"啊啊，來人，來人啊……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"나는 아무짓도 안 했어……. 나는, 나는 그저 우리 딸이, 숨을 쉬지 않아서……!","JPN":"私は何もしてない……私は、私はただ娘が、息をしないから……！","ENG":"I didn’t do anything... I, I just... My daughter, she wasn’t breathing so...!","TWN":"我什麼都沒做……我…我女兒…我女兒沒有呼吸……！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"허억, 숨이, 허어억……! 자, 잘못……! 잘못했어요……! 잘못했어요!!","JPN":"はあ、息が、はああっ……！　ゆ、許し……！　許して……！　ごめんなさい！！","ENG":"*Pant* I can’t... breathe! *Pant…!* I-I’m... I’m sorry...! I’m so sorry!!","TWN":"咳咳，呼吸…咳咳咳……！對…對不起…！都怪我不好……！都是我的錯！！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아주머니! 진정하고 숨을 크게 들이쉬세요! 아주머니!","JPN":"おばさん！　落ち着いて深呼吸をしてください！　おばさん！","ENG":"Madam! Just breathe! Take a deep breath! Madam!","TWN":"伯母！你冷靜一點，深呼吸！伯母！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"살려 줘……. 우리 딸, 우리 딸 좀 살려 줘어…….","JPN":"助けて……私の娘、娘を助けて……","ENG":"Somebody help... My daughter, somebody please help my daughter...","TWN":"救命……救救我女兒…我的女兒…"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_C","text":{"KOREA":"저기 있다!","JPN":"あそこだ！","ENG":"Over there!","TWN":"在那裡！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L19_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_D","text":{"KOREA":"늙은이는 그냥 쏴서 죽여 버려! 다른 두 년은 내가 손본다!","JPN":"老人は射殺しろ！　他の女どもは俺がやる！","ENG":"Just shoot the old woman! I’ll take care of the other two.","TWN":"把這老的幹掉吧！另外兩個女的交給我處理！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_D","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_D","text":{"KOREA":"어……? 나, 가슴이 왜, 찌그러…….","JPN":"あ……？　俺、なんで胸が、デコボコに……","ENG":"Hrgh...? What the... My chest... What’s happe...","TWN":"呃……？我…胸口好緊……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_VOICE_NULL_D","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_VOICE_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BASS_HARMONY_CHANGE_HIDE","text":{"KOREA":"더 다가오지 마세요. 안 그러면 저 분처럼 아프게 때려 줄 거예요.","JPN":"それ以上近づかないでください。そうじゃないとあの人のように痛い目に合いますよ。","ENG":"Don’t come any closer. If you do, I’ll do the same thing to you.","TWN":"不要再靠過來囉，否則你們的下場就會像他一樣。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_F","text":{"KOREA":"뭐, 뭐야? 저 커다란 건……? 첼로인가?","JPN":"な、何んだ？　あのデカいのは……？　チェロなのか？","ENG":"W-what?! What is that humongous thing...? Is that a cello?","TWN":"搞…搞什麼？那個巨大的東西是……？大提琴？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_F","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"BASS_HARMONY_CHANGE_HIDE","text":{"KOREA":"……첼로가 아니라 콘트라베이스랍니다.","JPN":"……チェロじゃなくてコントラバスです。","ENG":"...Not a cello. A contrabass.","TWN":"……這不是大提琴，是低音提琴。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BASS_HARMONY_CHANGE_HIDE","text":{"KOREA":"무례한 데다가 무식하기까지 하네요, 오늘의 관객 여러분께서는.","JPN":"失礼な上に無知ですね、今日の観客の皆さんは。","ENG":"Looks like today’s audience is not only rude, but ignorant as well.","TWN":"今天的觀眾不只是沒禮貌，還很沒知識呢！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그 귀랑 꼬리는……. 안젤라 씨, 카운터였어요?","JPN":"その耳と尻尾は……アンジェラさん、カウンターだったんですか？","ENG":"Those ears and tail... Angela... Are you a Counter?","TWN":"那個耳朵和尾巴……安潔拉小姐，你是制裁者嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_CHANGE_HIDE","text":{"KOREA":"말하지 않아서 미안해, 중사님. 그렇지만 이런 모습으로 다니면 피곤해지니까.","JPN":"言わなくてゴメンね、軍曹さん。でもこんな姿で出歩いてたら面倒な事になるから。","ENG":"I’m sorry for not telling you, Sergeant. But being in this form easily gets me involved in complicated stuff.","TWN":"抱歉，沒跟大家說。因為要是用這副模樣出入，會很不方便。"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"BASS_HARMONY_CHANGE_HIDE","text":{"KOREA":"중사님도 그렇지? 우리 둘만의 비밀로 하자?","JPN":"軍曹さんもそうじゃない？　二人だけの秘密にしよう？","ENG":"You’re one as well aren’t you, Sergeant? Let’s just let this be our little secret, shall we?","TWN":"但中士你不也是嗎？這就當作是我們兩個人之間的秘密吧？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하, 아하하…….","JPN":"はっ、あはは……","ENG":"Ha, a ha ha...","TWN":"哈哈哈……"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어떻게 알았어요? 그동안 한 번도 들킨 적 없는데……?","JPN":"どうしてわかったんですか？　今まで一度もバレたことないのに……","ENG":"How did you know? All this time, I’ve never been caught before...?","TWN":"你怎麼發現的？我還以為我隱藏得很好……？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"BASS_HARMONY_CHANGE_HIDE","text":{"KOREA":"척 하면 척이지. 언니는 카운터도 많이 만나 봤거든.","JPN":"見ればわかるわ。お姉ちゃんはカウンターにも結構会ったことがあるからね。","ENG":"It’s easy. I've met many Counters before.","TWN":"畢竟是裝的，姊姊也算是識制裁者無數好嗎？"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_CHANGE_HIDE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_F","text":{"KOREA":"칫……! 그래 봐야 조금 귀찮아진 정도지! 우리가 정부군 카운터 한두 놈 족친 줄 알아?","JPN":"ちっ……！　だとしても面倒ごとがちょっと増えただけだ！　こっちも政府軍のカウンターを何人もやってんだ！","ENG":"Tch...! Well, that’s not even irritating! You think we’ve never came across Counters before?","TWN":"嘖……！情況變得稍微棘手呢！沒想到我們有機會可以折磨政府軍的制裁者！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_F","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MERCENARY_VOICE_NULL_F","text":{"KOREA":"쏴 버려! 너희들 시체에 그 빌어먹을 년 낯짝을 처박아 주마!","JPN":"撃て！　てめぇらの死体にあのクソ女の顔を突っ込んでやる！","ENG":"Fire! Shoot them full of holes!","TWN":"開槍！我要在你們的屍體上刻上那女人的臉！"},"stage":{"bg":"GRONIA_STREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_VOICE_NULL_F","face":"UNIT_IDLE"},"R":{"char_id":"MERCENARY_VOICE_NULL_A","face":"UNIT_IDLE"}}}}]`);export{e as default};